  if (wOpp === 0) { out += NET_WS[6]; if (dMe <= dOpp) out += NET_WS[5]; }
  else if (wMe === 0) { out += NET_WS[8]; if (dOpp <= dMe - 1) out += NET_WS[7]; }
  if (dOpp <= 4) out += NET_WS[11] * (wMe < 3 ? wMe : 3);
  if (dMe <= 4) out += NET_WS[12] * (wOpp < 3 ? wOpp : 3);
